(function(){'use strict';if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',initializeComponents)}else{initializeComponents()}
function initializeComponents(){initReviewsCarousel();initPartnersSection();initTrustBar();initArticlesInteraction();initFaqSection()}
function initReviewsCarousel(){const reviewTrack=document.getElementById("reviewTrack");const reviewContainer=document.querySelector(".review-container");if(!reviewTrack||!reviewContainer){return}
let animationInterval;let isPaused=!1;let position=0;let containerWidth=reviewContainer.offsetWidth;let trackWidth=reviewTrack.scrollWidth;let scrollSpeed=1;reviewTrack.style.transition="transform 0.3s ease-out";reviewTrack.style.transform="translateX(0)";const reviewCards=reviewTrack.querySelectorAll(".review-card");function startAnimation(){if(animationInterval)clearInterval(animationInterval);animationInterval=setInterval(()=>{if(!isPaused){position-=scrollSpeed;if(position<-(trackWidth-containerWidth)){position=0;reviewTrack.style.transition="none";reviewTrack.style.transform=`translateX(${position}px)`;void reviewTrack.offsetHeight;reviewTrack.style.transition="transform 0.3s ease-out"}else{reviewTrack.style.transform=`translateX(${position}px)`}}},25)}
function pauseAnimation(){isPaused=!0}
function resumeAnimation(){isPaused=!1}
reviewCards.forEach(card=>{if(getComputedStyle(card).marginRight==="0px"){card.style.marginRight="1rem"}});reviewContainer.addEventListener("mouseenter",pauseAnimation);reviewContainer.addEventListener("mouseleave",resumeAnimation);window.addEventListener("resize",()=>{containerWidth=reviewContainer.offsetWidth;trackWidth=reviewTrack.scrollWidth;position=0;reviewTrack.style.transform="translateX(0)";startAnimation()});startAnimation()}
function initPartnersSection(){const toggleBtn=document.querySelector('.partners-mobile__toggle');if(!toggleBtn)return;const partnerGroups=document.querySelectorAll('.partners-mobile__group--hidden');if(!partnerGroups.length)return;let isExpanded=!1;let currentGroupIndex=0;toggleBtn.addEventListener('click',function(){if(!isExpanded){showNextGroup()}else{collapseAllGroups()}});function showNextGroup(){if(currentGroupIndex<partnerGroups.length){const nextGroup=partnerGroups[currentGroupIndex];loadPartnersInGroup(nextGroup);nextGroup.classList.remove('partners-mobile__group--hidden');nextGroup.classList.add('partners-mobile__group--visible');currentGroupIndex++;updateButtonState();setTimeout(()=>{nextGroup.scrollIntoView({behavior:'smooth',block:'nearest'})},50)}}
function loadPartnersInGroup(group){const lazyImages=group.querySelectorAll('.partners-section__logo[loading="lazy"]');lazyImages.forEach(img=>{if(img.dataset.src){img.src=img.dataset.src}
if(img.dataset.srcset){img.srcset=img.dataset.srcset}});const skeletons=group.querySelectorAll('.partners-section__skeleton');skeletons.forEach(skeleton=>{})}
function collapseAllGroups(){partnerGroups.forEach(group=>{group.classList.add('partners-mobile__group--hidden');group.classList.remove('partners-mobile__group--visible')});currentGroupIndex=0;updateButtonState();const partnersSection=document.getElementById('insurance-partners');if(partnersSection){partnersSection.scrollIntoView({behavior:'smooth',block:'nearest'})}}
function updateButtonState(){if(currentGroupIndex>=partnerGroups.length){toggleBtn.innerHTML='Show Less Partners <i class="fas fa-chevron-up ms-1"></i>';toggleBtn.classList.add('expanded');isExpanded=!0}else{toggleBtn.innerHTML='Show More Partners <i class="fas fa-chevron-down ms-1"></i>';toggleBtn.classList.remove('expanded');isExpanded=!1}}
updateButtonState();initLazyLoading();initPartnerCardAnimations();initResponsiveHandling();initPrintOptimizations();function initLazyLoading(){if(!('IntersectionObserver' in window)){loadAllPartnerImages();return}
const lazyImageObserver=new IntersectionObserver((entries)=>{entries.forEach((entry)=>{if(entry.isIntersecting){const lazyImage=entry.target;if(lazyImage.dataset.src){lazyImage.src=lazyImage.dataset.src}
if(lazyImage.dataset.srcset){lazyImage.srcset=lazyImage.dataset.srcset}
lazyImageObserver.unobserve(lazyImage)}})},{rootMargin:'200px 0px',threshold:0.01});const lazyImages=document.querySelectorAll('.partners-section__logo[loading="lazy"]');lazyImages.forEach((image)=>{lazyImageObserver.observe(image)})}
function loadAllPartnerImages(){const lazyImages=document.querySelectorAll('.partners-section__logo[loading="lazy"]');lazyImages.forEach((image)=>{if(image.dataset.src){image.src=image.dataset.src}
if(image.dataset.srcset){image.srcset=image.dataset.srcset}})}
function initPartnerCardAnimations(){if(window.matchMedia('(prefers-reduced-motion: reduce)').matches){return}
const cards=document.querySelectorAll('.partners-section__card');cards.forEach(card=>{card.addEventListener('mouseenter',handleCardEnter,{passive:!0});card.addEventListener('mouseleave',handleCardLeave,{passive:!0})});function handleCardEnter(){this.style.willChange='transform, box-shadow'}
function handleCardLeave(){setTimeout(()=>{this.style.willChange='auto'},200)}}
function initResponsiveHandling(){const mediaQuery=window.matchMedia('(min-width: 768px)');handleViewportChange(mediaQuery);mediaQuery.addEventListener('change',handleViewportChange);function handleViewportChange(e){if(e.matches){document.querySelectorAll('.partners-section__logo').forEach(img=>{})}else{const hiddenGroups=document.querySelectorAll('.partners-mobile__group--hidden');hiddenGroups.forEach(group=>{const resources=group.querySelectorAll('img, iframe, video');resources.forEach(resource=>{if(!resource.hasAttribute('loading')){resource.setAttribute('loading','lazy')}})})}}}
function initPrintOptimizations(){window.addEventListener('beforeprint',()=>{document.querySelectorAll('.partners-mobile__group--hidden').forEach(group=>{group.classList.remove('partners-mobile__group--hidden');group.classList.add('partners-mobile__group--temp-visible');group.querySelectorAll('img[loading="lazy"]').forEach(img=>{if(img.dataset.src){img.src=img.dataset.src}
if(img.dataset.srcset){img.srcset=img.dataset.srcset}})});document.querySelectorAll('.partners-section__logo').forEach(logo=>{logo.style.filter='none';logo.style.opacity='1'})});window.addEventListener('afterprint',()=>{document.querySelectorAll('.partners-mobile__group--temp-visible').forEach(group=>{group.classList.add('partners-mobile__group--hidden');group.classList.remove('partners-mobile__group--temp-visible')});document.querySelectorAll('.partners-section__logo').forEach(logo=>{logo.style.filter='';logo.style.opacity=''})})}}
function initTrustBar(){const scrollContainer=document.querySelector('.js-trust-bar-scroll');const trustBar=document.querySelector('.trust-bar');if(!scrollContainer||!trustBar)return;function toggleTrustBarAnimation(){if(window.innerWidth<768){trustBar.classList.add('trust-bar--animate')}else{trustBar.classList.remove('trust-bar--animate')}}
toggleTrustBarAnimation();setTimeout(toggleTrustBarAnimation,500);window.addEventListener('resize',toggleTrustBarAnimation);const mediaQuery=window.matchMedia('(prefers-reduced-motion: reduce)');function handleReducedMotionPreference(){if(mediaQuery.matches){trustBar.classList.remove('trust-bar--animate')}else{toggleTrustBarAnimation()}}
handleReducedMotionPreference();mediaQuery.addEventListener('change',handleReducedMotionPreference)}
function initArticlesInteraction(){const articleCards=document.querySelectorAll('.articles__card');if(!articleCards.length)return;articleCards.forEach(card=>{card.addEventListener('keydown',function(e){if(e.key==='Enter'||e.key===' '){e.preventDefault();this.click()}});card.setAttribute('role','article');card.setAttribute('aria-label',card.querySelector('.articles__title')?.textContent.trim());card.addEventListener('focus',function(){this.classList.add('focus-visible')});card.addEventListener('blur',function(){this.classList.remove('focus-visible')})});if('IntersectionObserver' in window){const cardObserver=new IntersectionObserver((entries)=>{entries.forEach(entry=>{if(entry.isIntersecting){entry.target.classList.add('in-viewport');const cardImage=entry.target.querySelector('.articles__image');if(cardImage&&cardImage.dataset.highres){const highResImage=new Image();highResImage.src=cardImage.dataset.highres;highResImage.onload=function(){cardImage.src=cardImage.dataset.highres}}
cardObserver.unobserve(entry.target)}})},{rootMargin:'0px 0px 100px 0px',threshold:0.1});articleCards.forEach(card=>{cardObserver.observe(card)})}}
function initFaqSection(){const faqContainer=document.getElementById('insuranceFAQ');if(!faqContainer)return;const faqItems=faqContainer.querySelectorAll('.faq__item');const faqButtons=faqContainer.querySelectorAll('.faq__question');function highlightActiveFaq(){faqItems.forEach(item=>{item.classList.remove('faq__item--active')});faqButtons.forEach(button=>{if(!button.classList.contains('collapsed')){button.closest('.faq__item').classList.add('faq__item--active')}})}
function enableKeyboardNavigation(){faqButtons.forEach(button=>{button.addEventListener('keydown',function(e){const buttons=Array.from(faqButtons);const currentIndex=buttons.indexOf(this);let nextIndex;switch(e.key){case 'ArrowDown':nextIndex=currentIndex<buttons.length-1?currentIndex+1:0;e.preventDefault();buttons[nextIndex].focus();break;case 'ArrowUp':nextIndex=currentIndex>0?currentIndex-1:buttons.length-1;e.preventDefault();buttons[nextIndex].focus();break;case 'Home':e.preventDefault();buttons[0].focus();break;case 'End':e.preventDefault();buttons[buttons.length-1].focus();break}})})}
function handleHashNavigation(){if(window.location.hash){const targetId=window.location.hash.substring(1);const targetElement=document.getElementById(targetId);if(targetElement&&targetElement.classList.contains('faq__answer')){const button=document.querySelector(`[aria-controls="${targetId}"]`);if(button&&button.classList.contains('collapsed')){button.click();setTimeout(()=>{targetElement.scrollIntoView({behavior:'smooth',block:'start'})},350)}}}}
faqContainer.addEventListener('shown.bs.collapse',highlightActiveFaq);faqContainer.addEventListener('hidden.bs.collapse',highlightActiveFaq);enableKeyboardNavigation();setTimeout(handleHashNavigation,100);highlightActiveFaq()}
function throttle(func,limit){let lastFunc;let lastRan;return function(){const context=this;const args=arguments;if(!lastRan){func.apply(context,args);lastRan=Date.now()}else{clearTimeout(lastFunc);lastFunc=setTimeout(function(){if((Date.now()-lastRan)>=limit){func.apply(context,args);lastRan=Date.now()}},limit-(Date.now()-lastRan))}}}})()